using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// Fix 1 – ValidateScopes now enabled in Development (new .NET 9 default).
//   A Singleton capturing a Scoped service is a captive-dependency bug that
//   was previously silent; it now throws at startup.  Change to Scoped.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Fix 2 – Default primary handler is now SocketsHttpHandler.
//   The cast to HttpClientHandler throws InvalidCastException.
//   Use ConfigurePrimaryHttpMessageHandler to supply the handler directly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new HttpClientHandler { UseCookies = false });

// Fix 3 – ForwardedHeadersMiddleware now ignores X-Forwarded-* from
//   proxies not listed in KnownProxies / KnownNetworks.
//   Add your actual reverse-proxy addresses here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Loopback);
});

// Fix 4 – Trace-level HttpClient logs now redact ALL header values.
//   Allowlist the non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id" && h != "X-Correlation-Id"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

// Stubs so the project compiles as a self-contained example.
public interface IUserService { }
public class UserService : IUserService { }
public interface ICacheService { }
public class CacheService(IUserService users) : ICacheService { }

